void greet(string name) {
  cout << "Hello " << name << "!\n";
}

int main() {
  greet("Liam");
  greet("Jenny");
  return 0;
}

void getBio(string name, int age) {
  cout << name << " is " << age << " years old.\n";
}

int main() {
  getBio("Liam", 3); 
  getBio("Jenny", 14);
  return 0;
}
